  document.getElementById('generateBtn').onclick = function() {
    if (!areaPolygon) return;
    setFooter('Generating incidents...');
    const count = parseInt(document.getElementById('incidentCount').value);
    const mode = document.getElementById('patternMode').value;

    stationLayer.clearLayers();
    coverageLayer.clearLayers();
    selectedStationLayer.clearLayers();
    stations = [];
    lastDemandGrid = null;
    lastPlanningResultMeta = null;
    modeResultCache = {};
    monteCarloResult = null;
    monteCarloInspectState = null;

    if (mode === 'uniform') incidents = generateUniform(count);
    else if (mode === 'clustered') incidents = generateClustered(count);
    else if (mode === 'corridor') incidents = generateCorridor(count);
    else if (mode === 'central') incidents = generateCentralPeak(count);
    else if (mode === 'perimeter') incidents = generatePerimeterBias(count);
    else if (mode === 'multi-corridor') incidents = generateMultiCorridor(count);
    else if (mode === 'grid') incidents = generateGridDemand(count);
    else if (mode === 'mixed') incidents = generateMixedUrban(count);
    else incidents = generateClustered(count);

    // Assign timestamps over the configured time window
    assignTimestamps(incidents, getKpiParams().periodHours);
    // Assign priorities based on configured mix
    assignPriorities(incidents, getPriorityMix());

    renderIncidents(null);

    setPanelState('panel2', 'active');
    setPanelState('panel3', null);
    document.getElementById('optimizeBtn').disabled = false;

    document.getElementById('status2').textContent = `${incidents.length} incidents · ${mode}`;
    document.getElementById('status2').classList.add('good');
    document.getElementById('status3').textContent = 'Ready to optimize';
    document.getElementById('status3').classList.remove('good');

    document.getElementById('m-incidents').textContent = incidents.length;
    document.getElementById('m-stations').textContent = '—';
    document.getElementById('m-coverage').textContent = '—';
    document.getElementById('m-units').textContent = '—';
    document.getElementById('m-kpi').textContent = '—';
    setDeploymentSnapshotVisible(false);
    clearStationReport();
    updateIncidentStats({ realTimestamps: false });
    syncStepNavButtons();
    setFooter(`${incidents.length} incidents placed`);
  };

  // ============ SAMPLE DATASET (evaluation) ============
  const SAMPLE_BANNER_DISMISS_KEY = 'sampleMissionBannerDismissed';
  function setSampleDataLoaded(on) {
    sampleDataLoaded = !!on;
    const banner = document.getElementById('sampleDataBanner');
    if (!banner) return;
    // A new mission load (or a reset) always clears any prior dismissal, so the
    // banner reappears for the freshly-loaded sample.
    try { localStorage.removeItem(SAMPLE_BANNER_DISMISS_KEY); } catch (e) {}
    banner.classList.remove('dismissing');
    banner.style.display = on ? 'flex' : 'none';
  }
  function dismissSampleBanner() {
    const banner = document.getElementById('sampleDataBanner');
    if (!banner) return;
    try { localStorage.setItem(SAMPLE_BANNER_DISMISS_KEY, '1'); } catch (e) {}
    banner.classList.add('dismissing'); // fade out
    setTimeout(function() { if (banner.classList.contains('dismissing')) banner.style.display = 'none'; }, 260);
  }

  // Loads a representative real-Dubai urban operational area (Downtown / Business
  // Bay / Bur Dubai, ~80 km²) plus ~250 SYNTHETIC incidents with a realistic
  // urban spatial pattern and a 30-day timestamp span — so evaluators can run the
  // tool end-to-end without uploading sensitive data. Geography is real Dubai;
  // the incidents are entirely fabricated (no real Dubai Police data).
  function loadSampleDataset() {
    resetAll();
    // Representative Dubai urban core (~80 km²): high-density commercial
    // (Downtown / Business Bay) plus mixed-use residential (Bur Dubai / Deira).
    const bounds = L.latLngBounds([25.18, 55.25], [25.27, 55.33]);
    const rect = L.rectangle(bounds, { color: '#7CDCE8', weight: 1.5, dashArray: '4,4', fillColor: '#7CDCE8', fillOpacity: 0.12 });
    handleAreaCreated(rect);
    if (map.fitBounds) map.fitBounds(bounds, { padding: [40, 40] });

    // ~250 synthetic incidents with a mixed-urban pattern (commercial-district
    // clusters plus scattered residential calls). Fast to compute end-to-end.
    incidents = generateMixedUrban(250);
    const spanHours = 720; // 30 days
    const anchorMs = Date.now() - spanHours * 3600000;
    assignTimestamps(incidents, spanHours);
    for (const inc of incidents) {
      const offsetH = (typeof inc.t === 'number') ? inc.t : Math.random() * spanHours;
      inc.timestamp = new Date(anchorMs + offsetH * 3600000).toISOString();
    }
    assignPriorities(incidents, getPriorityMix());

    renderIncidents(null);
    setPanelState('panel2', 'active');
    setPanelState('panel3', null);
    document.getElementById('optimizeBtn').disabled = false;
    const status2 = document.getElementById('status2');
    if (status2) { status2.textContent = `Sample mission: Dubai — ${incidents.length} synthetic incidents`; status2.classList.add('good'); }
    document.getElementById('m-incidents').textContent = incidents.length;
    document.getElementById('m-stations').textContent = '—';
    document.getElementById('m-coverage').textContent = '—';
    document.getElementById('m-units').textContent = '—';
    document.getElementById('m-kpi').textContent = '—';
    setDeploymentSnapshotVisible(false);
    clearStationReport();
    updateIncidentStats({ realTimestamps: true, anchorMs, spanHours });
    syncStepNavButtons();
    setSampleDataLoaded(true);
    setFooter('Sample mission: Dubai (representative geography, synthetic incidents) — for evaluation only');
  }

  const loadSampleBtn = document.getElementById('loadSampleBtn');
  if (loadSampleBtn) loadSampleBtn.onclick = loadSampleDataset;
  // The banner markup lives after this script in the DOM, so wire its dismiss
  // button once the document is parsed.
  (function wireSampleBannerDismiss() {
    function wire() {
      const btn = document.getElementById('sampleBannerDismiss');
      if (btn) btn.onclick = dismissSampleBanner;
    }
    if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', wire);
    else wire();
  })();

  function updateRadius() {
    const manual = inputRadiusToM(document.getElementById('manualRadius').value);
    let radius, isManual;
    if (manual && manual > 0) {
      radius = manual;
      isManual = true;
    } else {
      const speed = inputSpeedToMs(document.getElementById('droneSpeed').value);
      // Use the strictest EFFECTIVE fly-time across all categories. Overhead
      // (dock-open + sensor warmup + launch + climb) is subtracted from each
      // category's raw KPI so the radius reflects what the drone can actually
      // cover horizontally within the remaining time budget.
      const time = getStrictestEffectiveKpiSec();
      radius = speed * time;
      isManual = false;
    }
    const display = formatDistance(radius);
    const el = document.getElementById('radiusDisplay');
    if (el) {
      const overheadNote = isManual ? ' (manual)' : ` (after ${getGlobalOverheadSec()}s overhead)`;
      el.textContent = display + overheadNote;
    }
    return radius;
  }

  function dropPresetToCustom() {
    const sel = document.getElementById('minimizePreset');
    if (sel && sel.value !== 'custom') {
      sel.value = 'custom';
      const noteEl = document.getElementById('minimizePresetNote');
      if (noteEl) noteEl.textContent = '';
    }
  }
  document.getElementById('droneSpeed').oninput = function() { dropPresetToCustom(); updateRadius(); };
  document.getElementById('manualRadius').oninput = function() { dropPresetToCustom(); updateRadius(); };
  updateLocalizationLabels();
  updateRadius();

  document.getElementById('optimizeBtn').onclick = function() {
    syncPlanningModeStateFromControls();
    const planningMode = getSelectedPlanningMode();
    if (incidents.length === 0) {
      if (planningMode === PLANNING_MODE.SMOOTHED_GROWTH) {
        alert('Smoothed Demand needs incident data. Load an incident file or generate incidents first.');
        setFooter('Load or generate incidents first');
      }
      return;
    }
    if (optMode === 'fleet' && (fleetTypes.length === 0 || fleetTypes.every(t => (parseInt(t.count) || 0) === 0))) {
      setFooter('Add at least one drone type with a non-zero count');
      return;
    }
    if (planningMode === PLANNING_MODE.MONTE_CARLO) {
      const planning = getPlanningParams();
      const mcSettings = getMonteCarloSettings();
      monteCarloController = { cancelled: false };
      monteCarloResult = null;
      monteCarloInspectState = null;
      renderMonteCarloProgress(0, mcSettings.runCount);
      document.getElementById('optimizeBtn').disabled = true;
      document.getElementById('optimizeBtn').textContent = 'Running...';
      setFooter('Running Monte Carlo...');
      const temporalProbe = fitTemporalProfile(incidents, mcSettings);
      if (temporalProbe.warning) alert(temporalProbe.warning);
      runMonteCarloCore(planning, mcSettings, renderMonteCarloProgress)
        .then(result => {
          monteCarloResult = result;
          lastDemandGrid = result.demandGrid;
          lastPlanningResultMeta = {
            mode: PLANNING_MODE.MONTE_CARLO,
            settings: result.settings,
            demandGrid: {
              resolution: result.demandGrid.resolution,
              bandwidthMeters: result.demandGrid.bandwidthMeters,
              demandThresholdPct: result.demandGrid.demandThresholdPct,
              activeCellCount: result.demandGrid.activeCells.length,
              droppedCellCount: result.demandGrid.droppedCells
            },
            traceIncidentCount: Math.round(percentileFromValues(result.summaries.map(summaryItem => summaryItem.incidentCount), 0.5)),
            historicalIncidentCount: incidents.length,
            monteCarlo: {
              runCount: result.summaries.length,
              robustCoreCount: result.stationAggregation.robustCore.length,
              binMeters: result.binMeters,
              runtimeMs: result.runtimeMs
            }
          };
          selectedStationIndex = null;
          renderIncidents(null);
          renderMonteCarloVisualization();
          renderMonteCarloHeadline(result);
          renderMonteCarloDebugPanel();
          setPanelState('panel3', 'done');
          syncStepNavButtons();
          setFooter(`Monte Carlo complete - ${result.summaries.length} runs`);
        })
        .catch(err => {
          if (err && err.message === 'Monte Carlo cancelled') {
            setFooter('Monte Carlo cancelled');
            document.getElementById('status3').textContent = 'Monte Carlo cancelled';
            document.getElementById('status3').classList.remove('good');
          } else {
            console.error('Monte Carlo error:', err);
            setFooter('Monte Carlo failed - see browser console');
            alert('Monte Carlo failed: ' + (err && err.message ? err.message : err));
          }
        })
        .finally(() => {
          hideMonteCarloProgress();
          monteCarloController = null;
          document.getElementById('optimizeBtn').disabled = false;
          document.getElementById('optimizeBtn').textContent = 'Re-compute';
        });
      return;
    }
    setFooter(planningMode === PLANNING_MODE.SMOOTHED_GROWTH ? 'Computing smoothed demand deployment...' : 'Computing direct fit deployment...');
    document.getElementById('optimizeBtn').disabled = true;
    document.getElementById('optimizeBtn').textContent = 'Computing...';

    // Refresh zone caches once per run — used by all hot-path geometry checks
    computeZoneCaches();

    // Async to allow UI update
    setTimeout(function() {
      try {
        let result;
        const planning = getPlanningParams();
        const activeMode = getSelectedPlanningMode();
        result = activeMode === PLANNING_MODE.SMOOTHED_GROWTH
          ? runSmoothedGrowthDeployment(planning)
          : runDirectFitDeployment(planning);

        // Apply concurrency sizing (Erlang B) per cluster
        const kpi = getKpiParams();
        const remainingByType = (optMode === 'fleet') ? (result.remainingByType || {}) : null;
        const simulationIncidents = deploymentIncidentsForResult(result);
        applyConcurrency(result.stations, kpi, remainingByType, simulationIncidents);

        stations = result.stations;
        selectedStationIndex = null;
        renderStations(stations);
        lastDemandGrid = result.demandGrid || null;
        lastPlanningResultMeta = {
          mode: activeMode,
          settings: result.settings || null,
          demandGrid: result.demandGrid ? {
            resolution: result.demandGrid.resolution,
            bandwidthMeters: result.demandGrid.bandwidthMeters,
            demandThresholdPct: result.demandGrid.demandThresholdPct,
            activeCellCount: result.demandGrid.activeCells.length,
            droppedCellCount: result.demandGrid.droppedCells
          } : null,
          traceIncidentCount: simulationIncidents.length,
          historicalIncidentCount: incidents.length
        };
        if (activeMode === PLANNING_MODE.SMOOTHED_GROWTH) {
          heatmapEnabled = true;
          const heatmapToggle = document.getElementById('heatmapEnabled');
          if (heatmapToggle) heatmapToggle.checked = true;
        }
        const renderedCoverage = activeMode === PLANNING_MODE.SMOOTHED_GROWTH ? result.historicalCovered : result.covered;
        renderIncidents(renderedCoverage);

        setPanelState('panel3', 'done');

        const totalUnits = stations.reduce((s, x) => s + (x.units || 1), 0);
        const totalShortfall = stations.reduce((s, x) => s + (x.shortfall || 0), 0);
        const kpiCompliance = overallKpiCompliance(stations, simulationIncidents.length);
        const prioCompliance = compliancePerPriority(stations, simulationIncidents);
        const targets = getPriorityTargets();

        // Per-category compliance pills (one per defined category that has demand)
        const pillsHtml = incidentCategories.map(cat => {
          if ((prioCompliance.totals[cat.id] || 0) === 0) return '';
          const achieved = (prioCompliance[cat.id] || 0) * 100;
          const target = (targets[cat.id] || 0) * 100;
          const miss = achieved < target - 0.05;
          const shortName = cat.name.length > 6 ? cat.name.substring(0, 6) : cat.name;
          const fg = miss ? '#e38b95' : '#020609';
          const bg = miss ? 'transparent' : cat.color;
          const border = `1px solid ${cat.color}`;
          return `<span class="prio-pill" style="background:${bg};color:${miss ? cat.color : fg};border:${border};${miss ? 'text-decoration:line-through;' : ''}">${shortName} ${achieved.toFixed(0)}/${target.toFixed(0)}</span>`;
        }).join(' ');

        let statusText = `<strong>${totalUnits} DroneBox unit${totalUnits === 1 ? '' : 's'}</strong> across ${stations.length} site${stations.length === 1 ? '' : 's'}<br>${pillsHtml}`;
        if (activeMode === PLANNING_MODE.SMOOTHED_GROWTH) {
          const settings = result.settings || getSmoothedGrowthSettings();
          statusText += `<br>Mode: Smoothed Demand +${Math.round((settings.growthMultiplier - 1) * 100)}% volume | KDE ${result.demandGrid.activeCells.length} cells @ ${formatDistance(result.demandGrid.bandwidthMeters)}`;
          statusText += `<br>Weighted demand coverage: ${result.coveragePercent.toFixed(1)}% / ${planning.coverageTargetPct.toFixed(0)}% target`;
        } else {
          statusText += `<br>Mode: Direct Fit`;
          statusText += `<br>Geographic coverage: ${result.coveragePercent.toFixed(1)}% / ${planning.coverageTargetPct.toFixed(0)}% target`;
        }
        const networkLoad = buildNetworkLoadSummary();
        statusText += `<br>Network load: ${networkLoad.loadPct.toFixed(0)}% | queue risk ${networkLoad.queueRiskPct.toFixed(0)}% | peak hour ${formatHourLabel(networkLoad.peakHour)}`;
        if (!result.targetMet) {
          const stopLabel = activeMode === PLANNING_MODE.SMOOTHED_GROWTH
            ? `next station would add less than ${(result.minMarginalShare * 100).toFixed(1)}% of weighted demand`
            : `next station would cover fewer than ${planning.minIncidentsPerSite} incident${planning.minIncidentsPerSite === 1 ? '' : 's'}`;
          statusText += `<br><span style="color:var(--incident)">Target stopped early: ${stopLabel}</span>`;
        }
        if (optMode === 'fleet' && result.inventoryUsed) {
          const used = result.inventoryUsed.filter(t => t.used > 0).map(t => `${t.used}× ${t.name}`).join(' · ');
          if (used) statusText += '<br>Initial placement: ' + used;
          if (totalShortfall > 0) {
            statusText += `<br><span style="color:var(--incident)">⚠ Shortfall: ${totalShortfall} unit${totalShortfall === 1 ? '' : 's'} short of KPI target</span>`;
          }
        }
        document.getElementById('status3').innerHTML = statusText;
        document.getElementById('status3').classList.add('good');

        document.getElementById('m-stations').textContent = stations.length;
        document.getElementById('m-units').textContent = totalUnits;
        document.getElementById('m-coverage').innerHTML = result.coveragePercent.toFixed(1) + '<span class="metric-unit">%</span>';
        document.getElementById('m-kpi').innerHTML = (kpiCompliance * 100).toFixed(1) + '<span class="metric-unit">%</span>';
        setDeploymentSnapshotVisible(true);

        // Marginal-value curves
        const curve = computeMarginalCurves(stations, simulationIncidents);
        window.__lastCurve = curve; // saved for PDF export
        renderSaturationCurves(curve, planning);
        renderStationReportList();
        renderStationDetail(null);
        cacheCurrentPlanningResult();

        document.getElementById('optimizeBtn').disabled = false;
        document.getElementById('optimizeBtn').textContent = 'Re-compute';
        syncStepNavButtons();
        setFooter(`Deployment ready · ${stations.length} stations`);
      } catch (err) {
        console.error('Optimization error:', err);
        document.getElementById('optimizeBtn').disabled = false;
        document.getElementById('optimizeBtn').textContent = 'Compute Deployment';
        setFooter('Compute failed — see browser console for details');
        alert('Compute failed: ' + (err && err.message ? err.message : err) + '\nSee the browser console (F12) for the full trace.');
      }
    }, 30);
  };

  function resetAll() {
    setSampleDataLoaded(false);
    areaLayer.clearLayers();
    incidentLayer.clearLayers();
    stationLayer.clearLayers();
    coverageLayer.clearLayers();
    noFlyLayer.clearLayers();
    noDeployLayer.clearLayers();
    waterLayer.clearLayers();
    areaPolygon = null;
    incidents = [];
    stations = [];
    noFlyZones = [];
    noDeployZones = [];
    waterZones = [];
    __noFlyCache = [];
    __noDeployCache = [];
    __waterCache = [];
    lastDemandGrid = null;
    lastPlanningResultMeta = null;
    modeResultCache = {};
    monteCarloResult = null;
    monteCarloInspectState = null;
    updateNoFlyStatus();
    updateNoDeployStatus();
    updateWaterStatus();

    setPanelState('panel1', 'active');
    setPanelState('panel2', null);
    setPanelState('panel3', null);
    document.getElementById('generateBtn').disabled = true;
    document.getElementById('optimizeBtn').disabled = true;
    document.getElementById('optimizeBtn').textContent = 'Compute Deployment';
    const dlArea = document.getElementById('downloadArea');
    if (dlArea) dlArea.disabled = true;

    document.getElementById('status1').textContent = 'Awaiting area selection';
    document.getElementById('status1').classList.remove('good');
    document.getElementById('status2').textContent = 'No incident data';
    document.getElementById('status2').classList.remove('good');
    document.getElementById('status3').textContent = 'No deployment computed';
    document.getElementById('status3').classList.remove('good');

    ['m-area', 'm-incidents', 'm-stations', 'm-coverage', 'm-units', 'm-kpi'].forEach(id => {
      document.getElementById(id).textContent = '—';
    });
    setDeploymentSnapshotVisible(false);
    const statsBlock = document.getElementById('incidentStatsBlock');
    if (statsBlock) statsBlock.style.display = 'none';
    const chartBlock = document.getElementById('marginalChart');
    if (chartBlock) chartBlock.style.display = 'none';
    clearStationReport();
    window.__lastCurve = null;
    refreshHeatmap();
    setFooter('Idle');
    activateWorkflowStep(1);
  }

  document.getElementById('resetBtn').onclick = resetAll;

  document.getElementById('exportScheduleBtn').onclick = function() {
    if (stations.length === 0) {
      alert('Compute deployment before exporting the station schedule.');
      return;
    }
    const rows = [['rank','station','latitude','longitude','radius_m','units','incidents','kpi_percent']];
    stations.forEach((s, idx) => {
      rows.push([
        idx + 1,
        `DFR Station ${String(idx + 1).padStart(2, '0')}`,
        s.lat,
        s.lng,
        Math.round(s.radius || updateRadius()),
        s.units || 1,
        s.covered || (s.incidentIdx ? s.incidentIdx.length : 0),
        ((s.achievedServiceLevel || 0) * 100).toFixed(1)
      ]);
    });
    const csv = rows.map(row => row.map(v => `"${String(v).replace(/"/g, '""')}"`).join(',')).join('\n');
    triggerBlobDownload(new Blob([csv], { type: 'text/csv;charset=utf-8' }), `UASC_DFR_Station_Schedule_${new Date().toISOString().slice(0,10)}.csv`);
  };

  function latLngToPlain(ll) {
    return { lat: Number(ll.lat), lng: Number(ll.lng) };
  }

  function serializePolygon(layer) {
    if (!layer) return null;
    return polygonRings(layer).map(ring => ring.map(latLngToPlain));
  }

  function polygonFromSaved(rings, style) {
    if (!Array.isArray(rings) || rings.length === 0) return null;
    const latLngs = rings.map(ring => ring.map(pt => Array.isArray(pt)
      ? [Number(pt[1]), Number(pt[0])]
      : [Number(pt.lat), Number(pt.lng)]
    ));
    return L.polygon(latLngs, style || {});
  }

  function buildEditablePlanPayload() {
    if (!areaPolygon && stations.length === 0 && incidents.length === 0) {
      alert('Nothing to save. Define an area, load incidents, or compute a deployment first.');
      return null;
    }
    syncPlanningModeStateFromControls();
    const kpi = getKpiParams();
    const planning = getPlanningParams();
    const networkLoad = buildNetworkLoadSummary();
    const totalUnits = stations.reduce((s, x) => s + (x.units || 1), 0);
    const totalShortfall = stations.reduce((s, x) => s + (x.shortfall || 0), 0);
    const activeStep = parseInt((document.getElementById('app') && document.getElementById('app').dataset.step) || '1', 10) || 1;
    const includeAppendixJson = !!(document.getElementById('appendixJsonSnapshot') && document.getElementById('appendixJsonSnapshot').checked);
    return {
      fileType: 'uasc-dfr-plan',
      version: SAVED_PLAN_VERSION,
      savedAt: new Date().toISOString(),
      mode: optMode,
      planning_mode: getSelectedPlanningMode(),
      planningModeState: mergePlanningModeState({
        ...planningModeState,
        directFit: {
          ...planningModeState.directFit,
          coverageTargetPct: planning.coverageTargetPct,
          minIncidentsPerSite: planning.minIncidentsPerSite
        },
        smoothedGrowth: getSmoothedGrowthSettings(),
        monteCarlo: getMonteCarloSettings()
      }),
      planning_result_meta: lastPlanningResultMeta ? {
        ...lastPlanningResultMeta,
        demandGrid: lastPlanningResultMeta.demandGrid ? { ...lastPlanningResultMeta.demandGrid } : null
      } : null,
      smoothed_demand: lastDemandGrid ? {
        resolution: lastDemandGrid.resolution,
        bandwidth_meters: lastDemandGrid.bandwidthMeters,
        demand_threshold_pct: lastDemandGrid.demandThresholdPct,
        active_cell_count: lastDemandGrid.activeCells.length,
        dropped_cell_count: lastDemandGrid.droppedCells,
        total_raw_weight: lastDemandGrid.totalRawWeight,
        max_weight: lastDemandGrid.maxWeight
      } : null,
      monte_carlo: monteCarloResult ? {
        result_meta: {
          mode: monteCarloResult.mode,
          settings: monteCarloResult.settings,
          runtime_ms: monteCarloResult.runtimeMs,
          bin_meters: monteCarloResult.binMeters,
          robust_core_count: monteCarloResult.stationAggregation.robustCore.length,
          robust_core_load_pct: monteCarloRobustCoreLoadPct(monteCarloResult),
          retained_run_ids: monteCarloResult.retainedRunIds,
          intervals: monteCarloResult.intervals,
          station_frequency_bins: monteCarloResult.stationAggregation.bins.map(binInfo => ({
            frequency_pct: binInfo.frequencyPct,
            lat: binInfo.lat,
            lng: binInfo.lng,
            mean_units: binInfo.meanUnits,
            mean_load_pct: binInfo.meanLoadPct,
            run_hits: binInfo.runHits
          })),
          summaries: monteCarloResult.summaries
        },
        run_details: includeAppendixJson ? monteCarloResult.runRecords.map(record => ({
          summary: record.summary,
          stations: record.stations,
          syntheticIncidents: record.syntheticIncidents || null
        })) : null
      } : null,
      ui: {
        step: activeStep,
        unitSystem,
        coordFormat,
        incidentSource,
        heatmap: {
          enabled: heatmapEnabled,
          mode: heatmapMode,
          category: heatmapCategoryId,
          hour: heatmapHourFilter,
          month: heatmapMonthFilter
        }
      },
      mission_profile: {
        incident_period_h: kpi.periodHours,
        service_time_min: kpi.serviceTimeMin,
        dispatch_overhead_seconds: getGlobalOverheadSec(),
        geographic_coverage_target: planning.coverageTarget,
        min_incidents_per_site: planning.minIncidentsPerSite,
        planning_mode: getSelectedPlanningMode(),
        demand_growth_multiplier: getSmoothedGrowthSettings().growthMultiplier
      },
      inputs: {
        minimize_preset: document.getElementById('minimizePreset') ? document.getElementById('minimizePreset').value : 'custom',
        drone_speed: document.getElementById('droneSpeed') ? document.getElementById('droneSpeed').value : '',
        manual_radius: document.getElementById('manualRadius') ? document.getElementById('manualRadius').value : '',
        incident_count: document.getElementById('incidentCount') ? document.getElementById('incidentCount').value : '',
        distribution: document.getElementById('patternMode') ? document.getElementById('patternMode').value : 'clustered'
      },
      incident_categories: incidentCategories.map(c => ({
        id: c.id,
        name: c.name,
        color: c.color,
        kpi_seconds: c.kpiSec,
        effective_fly_time_seconds: effectiveFlyTimeSec(c),
        service_level_target: c.serviceLevel,
        weight: c.weight
      })),
      fleet_types: fleetTypes.map(t => ({
        id: t.id,
        catalogId: t.catalogId,
        name: t.name,
        radius: t.radius,
        speedKmh: t.speedKmh,
        serviceTimeMin: t.serviceTimeMin,
        count: t.count,
        notes: t.notes || '',
        color: t.color
      })),
      parameters: optMode === 'minimize' ? {
        drone_speed_mps: inputSpeedToMs(document.getElementById('droneSpeed').value),
        coverage_radius_m: updateRadius(),
        incident_count: incidents.length,
        distribution: document.getElementById('patternMode').value
      } : {
        fleet: fleetTypes.map(t => ({ name: t.name, radius_m: parseFloat(t.radius) || 0, count: parseInt(t.count) || 0 })),
        incident_count: incidents.length,
        distribution: document.getElementById('patternMode').value
      },
      summary: {
        sites: stations.length,
        total_dronebox_units: totalUnits,
        shortfall_units: totalShortfall,
        kpi_compliance_pct: 100 * overallKpiCompliance(stations, (lastPlanningResultMeta && lastPlanningResultMeta.traceIncidentCount) || incidents.length),
        network_load_pct: networkLoad.loadPct,
        network_availability_pct: networkLoad.availabilityPct,
        network_queue_risk_pct: networkLoad.queueRiskPct,
        network_peak_hour: networkLoad.peakHour,
        network_peak_hour_incidents: networkLoad.peakHourCount
      },
      area: areaPolygon ? {
        type: 'Polygon',
        coordinates: [(Array.isArray(areaPolygon.getLatLngs()[0]) ? areaPolygon.getLatLngs()[0] : areaPolygon.getLatLngs()).map(ll => [ll.lng, ll.lat])],
        area_km2: areaPolygon ? polygonAreaKm2(areaPolygon) : null,
        rings: serializePolygon(areaPolygon)
      } : null,
      constraints: {
        no_fly_zones: noFlyZones.length,
        no_deploy_zones: noDeployZones.length,
        water_exclusion_zones: waterZones.length,
        no_fly_zone_rings: noFlyZones.map(serializePolygon),
        no_deploy_zone_rings: noDeployZones.map(serializePolygon),
        water_exclusion_zone_rings: waterZones.map(serializePolygon)
      },
      incidents: incidents.map(i => ({ lat: i.lat, lng: i.lng, t: i.t, timestamp: i.timestamp || null, category: i.priority })),
      station_state: stations.map(s => ({
        lat: s.lat,
        lng: s.lng,
        covered: s.covered,
        incidentIdx: Array.isArray(s.incidentIdx) ? s.incidentIdx.slice() : [],
        demandIdx: Array.isArray(s.demandIdx) ? s.demandIdx.slice() : [],
        demandWeight: s.demandWeight || null,
        baselineCovered: s.baselineCovered || null,
        radius: s.radius,
        typeName: s.typeName,
        color: s.color,
        typeId: s.typeId,
        speedKmh: s.speedKmh,
        serviceTimeMin: s.serviceTimeMin,
        unitsRequired: s.unitsRequired,
        units: s.units,
        shortfall: s.shortfall || 0,
        peakConcurrent: s.peakConcurrent,
        achievedServiceLevel: s.achievedServiceLevel,
        achievedByPriority: s.achievedByPriority || {},
        clusterTotals: s.clusterTotals || {},
        priorityShortfall: s.priorityShortfall || {},
        avgResponseSec: s.avgResponseSec,
        loadMetrics: s.loadMetrics || {}
      })),
      sites: stations.map((s, idx) => ({
        id: idx + 1,
        lat: s.lat,
        lng: s.lng,
        type: s.typeName,
        radius_m: s.radius,
        incidents_covered: s.covered,
        units_required: s.unitsRequired,
        units_allocated: s.units,
        shortfall: s.shortfall || 0,
        peak_concurrent: s.peakConcurrent,
        expected_load_pct: s.loadMetrics ? s.loadMetrics.loadPct : 0,
        availability_pct: s.loadMetrics ? s.loadMetrics.availabilityPct : 0,
        peak_hour: s.loadMetrics ? s.loadMetrics.peakHour : null,
        peak_hour_incidents: s.loadMetrics ? s.loadMetrics.peakHourCount : 0,
        overlap_risk_pct: s.loadMetrics ? s.loadMetrics.overlapRiskPct : 0,
        queue_risk_pct: s.loadMetrics ? s.loadMetrics.queueRiskPct : 0,
        queued_incidents: s.loadMetrics ? s.loadMetrics.queuedIncidents : 0,
        max_queue_delay_min: s.loadMetrics ? s.loadMetrics.maxDelayMin : 0,
        service_level_achieved: s.achievedServiceLevel,
        per_category: incidentCategories.map(cat => ({
          id: cat.id,
          name: cat.name,
          incident_count: (s.clusterTotals && s.clusterTotals[cat.id]) || 0,
          service_level_achieved: (s.achievedByPriority && s.achievedByPriority[cat.id]) || 0,
          target: cat.serviceLevel,
          missed_target: !!(s.priorityShortfall && s.priorityShortfall[cat.id])
        }))
      }))
    };
  }

  document.getElementById('exportBtn').onclick = function() {
    const payload = buildEditablePlanPayload();
    if (!payload) return;
    const blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `UASC_DFR_Plan_${new Date().toISOString().slice(0,10)}.dfrplan.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  // ============ FLEET MODE ============
  const TYPE_COLORS = [
    '#dce6ef', '#9fb4c8', '#b79cf2', '#84cc16',
    '#ec4899', '#fb923c', '#14b8a6', '#f43f5e'
  ];
  let optMode = 'minimize';
  let fleetTypes = [];

  // ============ DRONE PLATFORM CATALOG ============
  // serviceTimeMin = total cycle time per call (typical mission ~10 min + downtime).
  // For autonomous swap platforms (Optimus, Percepto): ~10 min mission + swap.
  // For recharge platforms: ~10 min mission + recharge time.
  // ============ DRONE PLATFORM CATALOG ============
  // Values below are CALIBRATED to realistic DFR operations, not raw datasheet numbers.
  // Manufacturer specs inflate against real-world conditions: peak flight time
  // (54 min for M4D) assumes no payload, no wind, full charge, low altitude,
  // hot-to-cold dispatch. Operational reality strips ~40% of that budget:
  //   • Reserve margin (RTL trigger usually fires at 25-30% remaining battery)
  //   • Wind penalty (steady 15 km/h headwind costs ~15% endurance)
  //   • Payload + camera operation
  //   • Climb to operating altitude
  //   • Hovering on scene for the actual mission, not just transit
  //
  // The "radius" below is what the drone can REACH AND RETURN FROM with a
  // meaningful loiter window — not the round-trip ferry distance from datasheets.
  // A radius of 8km means: drone can fly 8km out, loiter ~5min, fly 8km back,
  // and still trigger RTL safely. This is what an operator can commit to a KPI.
  //
  // Speed is realistic cruise (typically 70-80% of datasheet max).
  // Cycle time = "service time" in the optimizer: end-of-call to next-call-ready,
  // including landing, charging-to-mission-ready threshold, pre-flight checks.
  const DRONE_CATALOG = [
    {
      id: 'dji-dock3-m4',
      name: 'DJI Dock 3 + Matrice 4D/4TD',
      vendor: 'DJI',
      radius: 7500,
      speedKmh: 45,
      serviceTimeMin: 40,
      notes: 'Spec: 54 min flight / 21 m/s max. Operator-reported: ~18 min usable at 10 km radius; 40 min recharge to ~80% mission-ready (full 95% takes ~55 min).'
    },
    {
      id: 'dji-dock2-m3',
      name: 'DJI Dock 2 + Matrice 3D/3TD',
      vendor: 'DJI',
      radius: 6000,
      speedKmh: 45,
      serviceTimeMin: 45,
      notes: 'Spec: 50 min flight / 21 m/s max. Operator-reported: 18-22 min usable at 5-6 km radius; ~45 min recharge to mission-ready.'
    },
    {
      id: 'skydio-dock-x10',
      name: 'Skydio Dock + X10',
      vendor: 'Skydio',
      radius: 5000,
      speedKmh: 50,
      serviceTimeMin: 35,
      notes: 'Spec: 40 min flight / 72 km/h max. Operator-reported: 20-25 min usable, conservative DFR radius 4-6 km. Recharge ~35 min.'
    },
    {
      id: 'optimus-amrobotics',
      name: 'Optimus (Ondas / American Robotics)',
      vendor: 'Ondas Autonomous Systems',
      radius: 5000,
      speedKmh: 55,
      serviceTimeMin: 6,
      notes: 'FAA Type Certified. Spec: 40 min flight / 30 sq mi area. Operator-reported: ~5 km effective DFR radius. Robotic battery swap ~3 min; 6 min realistic cycle including pre-flight.'
    },
    {
      id: 'percepto-air-max',
      name: 'Percepto Air Max + Base',
      vendor: 'Percepto',
      radius: 6500,
      speedKmh: 50,
      serviceTimeMin: 8,
      notes: 'Spec: 40 min flight / 16.5 km round-trip (~8.25 km radius) / 65 km/h. Operator-reported: ~6-7 km effective radius. Battery swap ~3 min plus pre-flight.'
    }
  ];

  function modeToggle(mode) {
    optMode = mode;
    document.querySelectorAll('.mode-tab[data-mode]').forEach(t => {
      t.classList.toggle('active', t.dataset.mode === mode);
    });
    document.getElementById('minimizePanel').style.display = (mode === 'minimize') ? 'block' : 'none';
    document.getElementById('fleetPanel').style.display = (mode === 'fleet') ? 'block' : 'none';
  }
  document.querySelectorAll('.mode-tab[data-mode]').forEach(t => {
    t.onclick = () => modeToggle(t.dataset.mode);
  });

  function escapeHtml(s) {
    return String(s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'})[c]);
  }

  function newTypeId() { return 't' + Date.now().toString(36) + Math.random().toString(36).substr(2, 4); }

  function addDroneType(opts) {
    opts = opts || {};
    const idx = fleetTypes.length;
    fleetTypes.push({
      id: newTypeId(),
      catalogId: opts.catalogId || 'custom',
      name: opts.name || `Custom Type ${String.fromCharCode(65 + idx)}`,
      radius: opts.radius || 1000,
      speedKmh: opts.speedKmh != null ? opts.speedKmh : 60,
      serviceTimeMin: opts.serviceTimeMin != null ? opts.serviceTimeMin : 15,
      count: opts.count != null ? opts.count : 3,
      notes: opts.notes || '',
      color: TYPE_COLORS[idx % TYPE_COLORS.length]
    });
    renderFleetList();
  }

  function applyPresetToType(typeId, catalogId) {
    const tt = fleetTypes.find(x => x.id === typeId);
    if (!tt) return;
    if (catalogId === 'custom') {
      tt.catalogId = 'custom';
      tt.notes = '';
      renderFleetList();
      return;
    }
    const preset = DRONE_CATALOG.find(p => p.id === catalogId);
    if (!preset) return;
    tt.catalogId = preset.id;
    tt.name = preset.name;
    tt.radius = preset.radius;
    tt.speedKmh = preset.speedKmh;
    tt.serviceTimeMin = preset.serviceTimeMin;
    tt.notes = preset.notes;
    renderFleetList();
  }

  function removeDroneType(id) {
    fleetTypes = fleetTypes.filter(t => t.id !== id);
    fleetTypes.forEach((t, i) => { t.color = TYPE_COLORS[i % TYPE_COLORS.length]; });
    renderFleetList();
  }

  function renderFleetList() {
    const container = document.getElementById('fleetList');
    container.innerHTML = '';
    fleetTypes.forEach(t => {
      const row = document.createElement('div');
      row.className = 'drone-type';
      row.dataset.id = t.id;

      const presetOptions = ['<option value="custom"' + (t.catalogId === 'custom' ? ' selected' : '') + '>Custom — enter manually</option>']
        .concat(DRONE_CATALOG.map(p =>
          `<option value="${p.id}"${t.catalogId === p.id ? ' selected' : ''}>${escapeHtml(p.name)}</option>`
        )).join('');

      row.innerHTML = `
        <div class="drone-type-header">
          <div class="type-badge" style="background:${t.color};"></div>
          <input class="type-name" value="${escapeHtml(t.name)}" data-field="name">
          <button class="type-remove" data-id="${t.id}" title="Remove type">×</button>
        </div>
        <div class="field" style="margin-bottom: 8px;">
          <label class="field-label">Platform Preset</label>
          <select class="type-preset" data-id="${t.id}">${presetOptions}</select>
        </div>
        <div class="drone-type-controls" style="grid-template-columns: 1fr 1fr 1fr;">
          <div class="field">
            <label class="field-label">Radius (m)</label>
            <input type="number" value="${t.radius}" min="100" data-field="radius">
          </div>
          <div class="field">
            <label class="field-label">Speed (km/h)</label>
            <input type="number" value="${t.speedKmh}" min="5" max="200" data-field="speedKmh">
          </div>
          <div class="field">
            <label class="field-label">Service Time (min)</label>
            <input type="number" value="${t.serviceTimeMin}" min="1" max="180" data-field="serviceTimeMin">
          </div>
        </div>
        <div class="drone-type-controls" style="margin-top: 6px;">
          <div class="field">
            <label class="field-label">Count</label>
            <input type="number" value="${t.count}" min="0" data-field="count">
          </div>
          <div class="field" style="display:flex;align-items:flex-end;">
            <div class="type-notes">${escapeHtml(t.notes || '')}</div>
          </div>
        </div>
      `;
      container.appendChild(row);
    });
    container.querySelectorAll('.type-remove').forEach(btn => {
      btn.onclick = () => removeDroneType(btn.dataset.id);
    });
    container.querySelectorAll('.type-preset').forEach(sel => {
      sel.onchange = function() {
        applyPresetToType(this.dataset.id, this.value);
      };
    });
    container.querySelectorAll('input[data-field]').forEach(inp => {
      inp.oninput = function() {
        const id = this.closest('.drone-type').dataset.id;
        const tt = fleetTypes.find(x => x.id === id);
        if (!tt) return;
        const field = this.dataset.field;
        if (field === 'name') tt.name = this.value;
        else tt[field] = parseFloat(this.value) || 0;
        // Any manual edit drops the catalog binding
        if (field !== 'name' && field !== 'count' && tt.catalogId !== 'custom') {
          tt.catalogId = 'custom';
          // Refresh dropdown selection without full redraw to preserve focus
          const sel = this.closest('.drone-type').querySelector('.type-preset');
          if (sel) sel.value = 'custom';
        }
        updateFleetSummary();
      };
    });
    updateFleetSummary();
  }

  function updateFleetSummary() {
    const total = fleetTypes.reduce((s, t) => s + (parseInt(t.count) || 0), 0);
    document.getElementById('fleetSummary').innerHTML =
      `<strong>${total}</strong> drone${total === 1 ? '' : 's'} across <strong>${fleetTypes.length}</strong> type${fleetTypes.length === 1 ? '' : 's'}`;
  }

  document.getElementById('addTypeBtn').onclick = function() { addDroneType(); };

  // Seed with one DJI Dock 3 entry (most common starting platform)
  addDroneType({ catalogId: 'dji-dock3-m4', name: DRONE_CATALOG[0].name, radius: DRONE_CATALOG[0].radius, speedKmh: DRONE_CATALOG[0].speedKmh, serviceTimeMin: DRONE_CATALOG[0].serviceTimeMin, notes: DRONE_CATALOG[0].notes, count: 3 });

  // ============ CALCULATE REQUIRED — PLATFORM PRESET ============
  // Populates the dropdown in the minimize panel with the same catalog used by Deploy Existing.
  (function populateMinimizePreset() {
    const sel = document.getElementById('minimizePreset');
    if (!sel) return;
    for (const p of DRONE_CATALOG) {
      const opt = document.createElement('option');
      opt.value = p.id;
      opt.textContent = p.name;
      sel.appendChild(opt);
    }
    sel.onchange = function() {
      const id = this.value;
      const speedInput = document.getElementById('droneSpeed');
      const radiusInput = document.getElementById('manualRadius');
      const noteEl = document.getElementById('minimizePresetNote');
      const cycleEl = document.getElementById('kpiServiceTime');
      if (id === 'custom') {
        if (noteEl) noteEl.textContent = '';
        // Don't overwrite user values when switching to custom
        updateRadius();
        return;
      }
      const preset = DRONE_CATALOG.find(p => p.id === id);
      if (!preset) return;
      // Catalog speed is stored as km/h; minimize panel displays localized speed.
      const speedMs = (preset.speedKmh * 1000 / 3600);
      speedInput.value = unitSystem === 'imperial' ? (speedMs / 0.44704).toFixed(1) : speedMs.toFixed(1);
      radiusInput.value = unitSystem === 'imperial' ? Math.round(preset.radius / 0.3048) : preset.radius;
      if (cycleEl) cycleEl.value = preset.serviceTimeMin;
      if (noteEl) noteEl.textContent = preset.notes || '';
      updateRadius();
    };
  })();

  // ============ HETEROGENEOUS GREEDY MAX COVERAGE ============
  function greedyHeterogeneous(incidents, types, planning) {
    const n = incidents.length;
    if (n === 0 || types.length === 0) {
      return { stations: [], covered: new Array(n).fill(false), coveragePercent: 0, inventoryUsed: [], remainingByType: {} };
    }
    planning = planning || getPlanningParams();
    const targetCount = requiredCoverageCount(n, planning);
    const minGain = Math.max(1, planning.minIncidentsPerSite || 1);

    // Working copy of inventory
    const inventory = types.map(t => ({
      id: t.id,
      name: t.name,
      radius: parseFloat(t.radius) || 0,
      speedKmh: parseFloat(t.speedKmh) || 60,
      serviceTimeMin: parseFloat(t.serviceTimeMin) || 15,
      color: t.color,
      total: parseInt(t.count) || 0,
      remaining: parseInt(t.count) || 0
    })).filter(t => t.radius > 0 && t.total > 0);

    // Distance matrix
    const dist = [];
    for (let i = 0; i < n; i++) {
      dist[i] = new Float32Array(n);
    }
    for (let i = 0; i < n; i++) {
      for (let j = i + 1; j < n; j++) {
        const d = haversine(incidents[i], incidents[j]);
        dist[i][j] = d;
        dist[j][i] = d;
      }
    }

    const covered = new Array(n).fill(false);
    let numCovered = 0;
    const stations = [];

    // Per-incident weight from priority
    const wts = incidents.map(inc => (getCategoryById(inc.priority).weight || 0));

    // Per-(type × incident) coverage radius. Each combination has its own radius:
    //   typeIncRadius[t][j] = min(type.radius, type.speedMs × effectiveKPI(incidents[j].category))
    // Capped at the type's own physical radius (an M4D can't fly past its battery
    // budget even if Routine category allows 1575m of fly-time math).
    const typeIncRadius = [];
    for (let t = 0; t < inventory.length; t++) {
      const speedMs = inventory[t].speedKmh / 3.6;
      const arr = new Float32Array(n);
      for (let j = 0; j < n; j++) {
        const cat = getCategoryById(incidents[j].priority);
        const effSec = effectiveFlyTimeSec(cat);
        const catRadius = speedMs * effSec;
        arr[j] = Math.min(inventory[t].radius, catRadius);
      }
      typeIncRadius.push(arr);
    }

    // Pre-compute candidate viability
    const candidateOk = incidents.map(inc => canDeployStation(inc));
    const hasNoFly = noFlyZones.length > 0;
    const standoff = incidents.map(inc => hasNoFly ? standoffPoint(inc) : inc);
    // Station-to-standoff distance matrix
    const respDist = [];
    for (let i = 0; i < n; i++) {
      respDist[i] = new Float32Array(n);
      for (let j = 0; j < n; j++) {
        respDist[i][j] = haversine(incidents[i], standoff[j]);
      }
    }
    // Memoize flight-path blockage results (see greedyMaxCoverage for rationale)
    const fpStatus = hasNoFly ? new Array(n) : null;
    if (hasNoFly) {
      for (let i = 0; i < n; i++) fpStatus[i] = new Uint8Array(n);
    }
    function isBlocked(i, j) {
      if (!hasNoFly) return false;
      const s = fpStatus[i][j];
      if (s === 1) return false;
      if (s === 2) return true;
      const blocked = flightPathBlocked(incidents[i], standoff[j]);
      fpStatus[i][j] = blocked ? 2 : 1;
      return blocked;
    }

    while (numCovered < targetCount) {
      const available = inventory.filter(t => t.remaining > 0);
      if (available.length === 0) break;

      let bestType = null;
      let bestSet = [];
      let bestLocIdx = -1;
      let bestWeight = 0;

      for (const type of available) {
        const typeIdx = inventory.indexOf(type);
        const radiusArr = typeIncRadius[typeIdx];
        for (let i = 0; i < n; i++) {
          if (!candidateOk[i]) continue;
          const distRow = respDist[i];
          const candidateSet = [];
          let candidateWeight = 0;
          for (let j = 0; j < n; j++) {
            if (covered[j]) continue;
            // Per-category-radius check, indexed by type AND incident
            if (distRow[j] > radiusArr[j]) continue;
            if (isBlocked(i, j)) continue;
            candidateSet.push(j);
            candidateWeight += wts[j];
          }
          if (candidateWeight > bestWeight ||
              (candidateWeight === bestWeight && candidateSet.length > bestSet.length)) {
            bestSet = candidateSet;
            bestType = type;
            bestLocIdx = i;
            bestWeight = candidateWeight;
          }
        }
      }

      if (bestType === null || bestSet.length === 0) break;
      if (bestSet.length < minGain) break;

      // Centroid refinement (respects flight paths and no-deploy)
      let cLat = 0, cLng = 0;
      for (const j of bestSet) { cLat += incidents[j].lat; cLng += incidents[j].lng; }
      cLat /= bestSet.length;
      cLng /= bestSet.length;
      const centroidPoint = { lat: cLat, lng: cLng };

      const centroidCovered = [];
      const centroidViable = canDeployStation(centroidPoint);
      if (centroidViable) {
        const typeIdx = inventory.indexOf(bestType);
        const radiusArr = typeIncRadius[typeIdx];
        for (let j = 0; j < n; j++) {
          if (covered[j]) continue;
          if (haversine(centroidPoint, standoff[j]) > radiusArr[j]) continue;
          if (hasNoFly && flightPathBlocked(centroidPoint, standoff[j])) continue;
          centroidCovered.push(j);
        }
      }

      let finalLoc, finalSet;
      if (centroidViable && centroidCovered.length >= bestSet.length) {
        finalLoc = centroidPoint;
        finalSet = centroidCovered;
      } else {
        finalLoc = incidents[bestLocIdx];
        finalSet = bestSet;
      }

      stations.push({
        lat: finalLoc.lat,
        lng: finalLoc.lng,
        covered: finalSet.length,
        incidentIdx: finalSet.slice(),
        radius: bestType.radius,
        typeName: bestType.name,
        color: bestType.color,
        typeId: bestType.id,
        speedKmh: bestType.speedKmh,
        serviceTimeMin: bestType.serviceTimeMin
      });
      bestType.remaining--;
      for (const j of finalSet) {
        if (!covered[j]) { covered[j] = true; numCovered++; }
      }
    }

    const inventoryUsed = inventory.map(t => ({ name: t.name, used: t.total - t.remaining, total: t.total }));
    const remainingByType = {};
    for (const t of inventory) remainingByType[t.id] = t.remaining;
    return {
      stations,
      covered,
      coveragePercent: 100 * numCovered / n,
      inventoryUsed,
      remainingByType,
      targetCoveragePercent: planning.coverageTargetPct,
      minIncidentsPerSite: minGain,
      targetMet: numCovered >= targetCount
    };
  }

  // ============ NO-FLY ZONE MANAGEMENT ============
  function addNoFlyZone(polygon) {
    polygon.setStyle({ color: '#FF6B7E', weight: 1.5, fillColor: '#FF6B7E', fillOpacity: 0.15, dashArray: null });
    noFlyLayer.addLayer(polygon);
    noFlyZones.push(polygon);
    __noFlyCache = []; // invalidate
    updateNoFlyStatus();
  }

  function clearAllNoFlyZones() {
    noFlyLayer.clearLayers();
    noFlyZones = [];
    __noFlyCache = [];
    updateNoFlyStatus();
  }

  function updateNoFlyStatus() {
    const el = document.getElementById('statusNoFly');
    const dl = document.getElementById('downloadNoFly');
    if (noFlyZones.length === 0) {
      el.textContent = 'No no-fly zones';
      el.classList.remove('good');
      if (dl) dl.disabled = true;
    } else {
      el.textContent = `${noFlyZones.length} no-fly zone${noFlyZones.length === 1 ? '' : 's'} active`;
      el.classList.add('good');
      if (dl) dl.disabled = false;
    }
  }

  function addNoDeployZone(polygon) {
    polygon.setStyle({ color: '#E8A744', weight: 1.5, fillColor: '#E8A744', fillOpacity: 0.15, dashArray: '4,4' });
    noDeployLayer.addLayer(polygon);
    noDeployZones.push(polygon);
    __noDeployCache = [];
    updateNoDeployStatus();
  }

  function clearAllNoDeployZones() {
    noDeployLayer.clearLayers();
    noDeployZones = [];
    __noDeployCache = [];
    updateNoDeployStatus();
  }

  function updateNoDeployStatus() {
    const el = document.getElementById('statusNoDeploy');
    const dl = document.getElementById('downloadNoDeploy');
    if (noDeployZones.length === 0) {
      el.textContent = 'No no-deploy zones';
      el.classList.remove('good');
      if (dl) dl.disabled = true;
    } else {
      el.textContent = `${noDeployZones.length} no-deploy zone${noDeployZones.length === 1 ? '' : 's'} active`;
      el.classList.add('good');
      if (dl) dl.disabled = false;
    }
  }

  function addWaterZone(polygon) {
    polygon.setStyle({ color: '#7CDCE8', weight: 1.5, fillColor: '#7CDCE8', fillOpacity: 0.12, dashArray: '2,3' });
    waterLayer.addLayer(polygon);
    waterZones.push(polygon);
    __waterCache = [];
    updateWaterStatus();
  }

  function clearAllWaterZones() {
    waterLayer.clearLayers();
    waterZones = [];
    __waterCache = [];
    updateWaterStatus();
  }

  function updateWaterStatus() {
    const el = document.getElementById('statusWater');
    const dl = document.getElementById('downloadWater');
    if (!el) return;
    if (waterZones.length === 0) {
      el.textContent = 'No water exclusions';
      el.classList.remove('good');
      if (dl) dl.disabled = true;
    } else {
      el.textContent = `${waterZones.length} water exclusion polygon${waterZones.length === 1 ? '' : 's'} active`;
      el.classList.add('good');
      if (dl) dl.disabled = false;
    }
  }

  function addWaterGeoJson(geo) {
    const features = geo.type === 'FeatureCollection' ? geo.features : [geo];
    let added = 0;
    for (const feature of features) {
      const geom = feature && feature.geometry;
      if (!geom) continue;
      if (geom.type === 'Polygon') {
        const rings = geom.coordinates.map(geoJsonRingToLatLngs).filter(r => r.length >= 3);
        if (rings.length === 0) continue;
        addWaterZone(L.polygon(rings.map(ring => ring.map(pt => [pt.lat, pt.lng]))));
        added++;
      } else if (geom.type === 'MultiPolygon') {
        for (const poly of geom.coordinates) {
          const rings = poly.map(geoJsonRingToLatLngs).filter(r => r.length >= 3);
          if (rings.length === 0) continue;
          addWaterZone(L.polygon(rings.map(ring => ring.map(pt => [pt.lat, pt.lng]))));
          added++;
        }
      }
    }
    return added;
  }

  // ============ DRAW NO-FLY ZONE ============
  document.getElementById('drawNoFlyBtn').onclick = function() {
    const btn = document.getElementById('drawNoFlyBtn');
    if (drawMode === 'polygon' && window.__drawTarget === 'nofly') {
      exitDrawing();
      return;
    }
    startDrawing('polygon');
    // Must set target AFTER startDrawing — startDrawing→exitDrawing resets it to 'area'
    window.__drawTarget = 'nofly';
    setActiveDrawBtn(null);
    btn.classList.add('active');
    setFooter('Drawing no-fly zone · double-click to finish');
  };

